      <YAxis
        mirror
        orientation="right"
        tickLine={false}
        tick={{ angle: 90, textAnchor: 'start' }}
        padding={{ bottom: 30 }}
      />
      <Bar
        dataKey="y"
        isAnimationActive={isAnimationActive}
        activeBar={AnimatedShape}
